const express = require('express');
const axios = require('axios');
const app = express();
const PORT = process.env.PORT || 3000;

// Allowlist of valid API keys
const validApiKeys = new Set(['your-valid-api-key-1', 'your-valid-api-key-2']);

// Middleware for API key authentication
app.use((req, res, next) => {
  const apiKey = req.query.api_key;
  if (!apiKey || !validApiKeys.has(apiKey)) {
    return res.status(403).json({ error: 'Forbidden: Invalid API Key' });
  }
  req.apiKey = apiKey; // Store validated API key for forwarding
  next();
});

// Middleware for logging requests
app.use((req, res, next) => {
  console.log(`Request: ${req.method} ${req.url} - API Key: ${req.apiKey}`);
  next();
});

// Forward requests to backend services
app.use('/api', async (req, res) => {
  try {
    const targetUrl = 'http://backend-service-url' + req.url;
    const response = await axios({
      method: req.method,
      url: targetUrl,
      headers: {
        ...req.headers,
        'X-API-Key': req.apiKey // Forward the API key securely
      },
      data: req.body
    });
    res.status(response.status).send(response.data);
  } catch (error) {
    console.error('Error forwarding request:', error.message);
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
});